mcqs.question:
What will be the output of the following code?
#include <iostream>
using namespace std;
int main() {
    int a = 7, b = 2;
    cout << a / b << endl;
    return 0;
}

What is the output of the following code?
#include <iostream>
using namespace std;
int main() {
    int x = 10;
    cout << sizeof(x) << " " << sizeof(x + 5.5);
    return 0;
}

What will be printed when the following code is executed?
#include <iostream>
using namespace std;
int main() {
    unsigned int a = -5;
    cout << a;
    return 0;
}

Consider the following code:
#include <iostream>
using namespace std;
int main() {
    int x = 10;
    int y = ++x + x++;
    cout << y;
    return 0;
}
Assuming left-to-right evaluation, what is the output?
